#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long sum = 0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            sum += x;
        }
        printf("%lld\n", sum / N);
    }
    return 0;
}

